INSERT OR IGNORE INTO todos (id, title, description) VALUES
('audio-fixes', 'Fix audio: ascending hop blip, turtle dive sound, pulsing timer warning, background music for gameplay and idle', 'Modify js/audio.js: 1) playHop() should use ascending frequency ramp (e.g. 400->800Hz). 2) Add playTurtleDive() bubbling sound. 3) playTimerWarning() should pulse/repeat. 4) Add background music: looping bass melody for gameplay, different melody for idle, stop on pause/gameover. Call from game.js state transitions.'),
('game-logic-fixes', 'Fix game logic: time bonus scoring, turtle dive frequency per level, fixed-timestep game loop', '1) scoring.js: add timeBonus() method (1pt per 10 ticks). Call in game.js handlePostDeath() and handleHomeArrival(). 2) spawner.js: increaseSpeeds() should also decrease diveInterval per level. 3) game.js: implement fixed-timestep accumulator pattern for game updates (separate from render rate).'),
('visual-fixes', 'Fix visuals: level complete staggered animation, reduced-motion ladybug bobbing, 200% zoom support', '1) renderer.js: drawLevelCompleteOverlay() should animate frog icons filling slots with stagger. 2) renderer.js: disable ladybug bobbing when reducedMotion is true. 3) index.html: change viewport meta to allow zooming (remove user-scalable=no).'),
('accessibility-fixes', 'Fix accessibility: make canvas sole focusable element', 'In index.html, add tabindex="-1" to mute button and all D-pad buttons so canvas remains the sole focusable game element.'),
('file-structure', 'Create missing files: vehicle.js, platform.js, sprite sheets placeholder', '1) Create js/vehicle.js with Car, Truck, Bulldozer classes (extract from lane.js/spawner.js). 2) Create js/platform.js with Log, Turtle classes (extract from spawner.js). 3) Create assets/ directory with placeholder or note that procedural rendering is used instead of sprite sheets.'),
('e2e-tests', 'Create missing e2e test specs: river-mechanics, road-mechanics, scoring', 'Create e2e/river-mechanics.spec.js, e2e/road-mechanics.spec.js, e2e/scoring.spec.js following existing patterns in e2e/ directory.'),
('validate-tests', 'Run all tests to validate changes', 'Run npm run test:all and fix any failures.')
